-- ----------------------------
-- View structure for studentview
-- ----------------------------
DROP VIEW IF EXISTS `studentview`;
CREATE ALGORITHM = UNDEFINED SQL SECURITY DEFINER VIEW `studentview` AS select `a`.`Id` AS `Id`,`a`.`StudentType` AS `StudentType`,`a`.`StudentAccount` AS `StudentAccount`,`a`.`StudentPwd` AS `StudentPwd`,`a`.`StandId` AS `StandId`,`a`.`ExamName` AS `ExamName`,`a`.`SchoolId` AS `SchoolId`,`a`.`CollegeId` AS `CollegeId`,`a`.`MajorId` AS `MajorId`,`a`.`ClassId` AS `ClassId`,`a`.`TrueName` AS `TrueName`,`a`.`IDNumber` AS `IDNumber`,`a`.`ExamNumber` AS `ExamNumber`,`a`.`Birthday` AS `Birthday`,`a`.`Phone` AS `Phone`,`a`.`Email` AS `Email`,`a`.`IDImage` AS `IDImage`,`a`.`FaceOpen` AS `FaceOpen`,ifnull(`b`.`SchoolName`,'') AS `SchoolName`,ifnull(`c`.`CollegeName`,'') AS `CollegeName`,ifnull(`d`.`MajorName`,'') AS `MajorName`,ifnull(`e`.`ClassName`,'') AS `ClassName`,ifnull(`f`.`StandName`,'') AS `StandName`,`a`.`Sex` AS `Sex`,`a`.`NativePlace` AS `NativePlace`,`a`.`RemainImg` AS `RemainImg` from (((((`student` `a` left join `school` `b` on((`a`.`SchoolId` = `b`.`Id`))) left join `college` `c` on((`a`.`CollegeId` = `c`.`Id`))) left join `major` `d` on((`a`.`MajorId` = `d`.`MajorId`))) left join `class` `e` on((`a`.`ClassId` = `e`.`Id`))) left join `stand` `f` on((`a`.`StandId` = `f`.`Id`)));

SET FOREIGN_KEY_CHECKS = 1;
