INSERT INTO `question` VALUES (1, 1, 1, '测试数学', 11, '{\"originMath\":\"\\\\text{计算以下不定积分：}\\\\quad\\\\int\\\\frac{x}{\\\\sqrt{1+x^2}}\\\\,dx\\\\quad\\\\text{，提示：令}\\\\ u=1+x^2\"}', 1, 0, 0, 0, '\"\\\\int\\\\frac{x}{\\\\sqrt[2]{1+x^2}}\\\\,dx=\\\\sqrt[2]{1+x^2}+C\"', 0, 0, '');
INSERT INTO `question` VALUES (2, 1, 1, '求概率', 11, '{\"originMath\":\"\\\\displaylines{设两次掷骰子的点数分别为𝑋1X1和𝑋2X2，\\\\\\\\ 每次点数均为1,2,3,4,5,61,2,3,4,5,6，且独立均匀分布。}\"}', 1, 0, 0, 0, '\"\\\\displaylines{设两次掷骰子的点数分别为X_1和X_2，\\\\\\\\ 每次点数均为1,2,3,4,5,6，且独立均匀分布。\\\\\\\\ 事件定义：\\\\\\\\ \\\\begin{cases}A=\\\\{X_1>X_2\\\\}\\\\\\\\ B=\\\\{X_1=X_2\\\\}\\\\\\\\ C=\\\\{X_1+X_2=7\\\\}\\\\end{cases}\\\\\\\\ 对应概率为：\\\\\\\\ \\\\begin{aligned}P(A) & =\\\\frac{15}{36}=\\\\frac{5}{12}\\\\\\\\ P(B) & =\\\\frac{6}{36}=\\\\frac16\\\\\\\\ P(C) & =\\\\frac{6}{36}=\\\\frac16\\\\end{aligned}}\"', 0, 0, '');
INSERT INTO `question` VALUES (3, 1, 1, '计算概率', 11, '{\"originMath\":\"\\\\displaylines{设连续型随机变量X的亲度函数为：P_2\\\\left(x\\\\right)=\\\\begin{cases}\\\\frac{2}{\\\\pi\\\\left(1+x_{^{}}^2\\\\right)},x>0\\\\\\\\ 0,x<0\\\\end{cases},\\\\\\\\ 求概率P\\\\left\\\\lbrace\\\\text{ X\\\\textasciicircum2}<=\\\\text{ }3\\\\right\\\\rbrace}\"}', 3, 0, 0, 0, '\"\\\\int_{-\\\\sqrt3}^0\\\\!0\\\\,dx\\\\text{ }\\\\int_0^{\\\\sqrt3}\\\\!\\\\frac{2}{\\\\pi *\\\\left(1+x^2\\\\right)}\\\\,dx,x^2\\\\le3\"', 0, 0, '\n');
